import React, {useState, useEffect} from "react";
import "./uploadposterCSS.css";
import Navbaremployee from "./upperlistemployee";
import Cookies from "universal-cookie";

export const UploadPoster = () => {
    const [search, setSearch] = useState('');
    const cookies=new Cookies();
    
    useEffect(() => {
        cookies.set('search',search,{path:'/'});
        console.log(cookies)
    },[search])

    const [imageUrl, setImageUrl] = useState('');
    const [isImageValid, setIsImageValid] = useState(false);

    const handleChange = (event) => {
        setImageUrl(event.target.value);
    };

    const handleImageLoad = () => {
        setIsImageValid(true);
    };
    
    return(
        <>
            {/* <Navbaremployee setSearch={setSearch}/> */}
            {/* https://ottaster.com/js-upload-file/ */}
            <input type="text" value={imageUrl} onChange={handleChange} />
            <br />

            {isImageValid ? (
                <img src={imageUrl} alt="" onLoad={handleImageLoad} />
            ) : (
                imageUrl && <span>Invalid image URL</span>
            )}
        </>
    );
};
export default UploadPoster;
